      setTimeout(() => {
        const user = mockUsers[0]; // Simulate first user login
        localStorage.setItem('typearena_user', JSON.stringify(user));
        resolve(user);
      }, 500);
    });
  } catch (error) {
    console.error('Login error:', error);
    throw error;
  }
};

