  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/auth/signup`, {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({ username, email, password, phoneNumber }),
    // });
    // return response.json();
    
    // Mock implementation
    return new Promise((resolve) => {
      setTimeout(() => {
        const newUser = {
          id: mockUsers.length + 1,
          username,
          email,
          phoneNumber,
          wpm: 0,
          accuracy: 0,
          totalRaces: 0,
          wins: 0,
          balance: 0,
        };
        localStorage.setItem('typearena_user', JSON.stringify(newUser));
        resolve(newUser);
      }, 500);
    });
  } catch (error) {
    console.error('Signup error:', error);
    throw error;
  }
};

// Tournament APIs
export const fetchTournaments = async () => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/tournaments`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockTournaments.map((t) => ({ ...t }))), 300);
    });
  } catch (error) {
    console.error('Error fetching tournaments:', error);
    return [];
  }
};

export const joinTournament = async (tournamentId) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/tournaments/${tournamentId}/join`, {
    //   method: 'POST',
    // });
    // return response.json();
    
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const tournament = mockTournaments.find((t) => t.id === tournamentId);
        if (!tournament) {
          reject(new Error('Tournament not found.'));
          return;
        }

        if (tournament.participants >= tournament.maxParticipants) {
          reject(new Error('This tournament is already full.'));
          return;
        }

        const storedUser = localStorage.getItem('typearena_user');
        if (!storedUser) {
          reject(new Error('Please sign in first to join this tournament.'));
          return;
        }

        const currentUser = JSON.parse(storedUser);
        if ((currentUser.balance ?? 0) < tournament.entryFee) {
          reject(new Error(`Insufficient balance. You need KES ${tournament.entryFee} to join.`));
          return;
        }

        const updatedUser = {
          ...currentUser,
          balance: currentUser.balance - tournament.entryFee,
        };
        localStorage.setItem('typearena_user', JSON.stringify(updatedUser));

        tournament.participants += 1;
        const isNowFull = tournament.participants >= tournament.maxParticipants;
        if (isNowFull) {
          tournament.status = 'active';
          tournament.startTime = new Date();
        }

        resolve({
          success: true,
          tournament: { ...tournament },
          user: updatedUser,
          message: isNowFull
            ? 'You have successfully joined this tournament. All required members have joined and the tournament is now starting.'
            : 'You have successfully joined this tournament. You will receive notification when it will start.',
        });
      }, 450);
    });
  } catch (error) {
    console.error('Error joining tournament:', error);
    throw error;
  }
};

// Leaderboard APIs
export const fetchLeaderboard = async (limit = 100) => {
  try {
    // TODO: Replace with actual API call
    // const response = await fetch(`${API_BASE_URL}/leaderboard?limit=${limit}`);
    // return response.json();
    
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockLeaderboard), 300);
    });
  } catch (error) {
    console.error('Error fetching leaderboard:', error);
    return [];
  }
};

