export const addFundsToWallet = async (amount) => {
  try {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const storedUser = localStorage.getItem('typearena_user');
        if (!storedUser) {
          reject(new Error('Please sign in first.'));
          return;
        }

        const parsedAmount = Number(amount);
        if (!Number.isFinite(parsedAmount) || parsedAmount <= 0) {
          reject(new Error('Enter a valid amount greater than zero.'));
          return;
        }

        const user = JSON.parse(storedUser);
        const updatedUser = {
          ...user,
          balance: Number(user.balance || 0) + parsedAmount,
        };

        localStorage.setItem('typearena_user', JSON.stringify(updatedUser));
        resolve(updatedUser);
      }, 250);
    });
  } catch (error) {
    console.error('Error adding funds:', error);
    throw error;
  }
};
